   (	"CRF_NAME" VARCHAR2(100),
	"SEQUENCE" NUMBER(2,0),
	"SECTION_NAME" VARCHAR2(4000)
   ) ;
--------------------------------------------------------
--  DDL for Table STD_SECTIONS
--------------------------------------------------------

  CREATE TABLE "STD_SECTIONS"
   (	"SECTION_NAME" VARCHAR2(100),
	"SECTION_DESCRIPTION" VARCHAR2(4000),
	"SECTION_KEY" VARCHAR2(100),
	"MULTIPLE_RECORDS_FLAG" VARCHAR2(10)
   ) ;
--------------------------------------------------------
--  DDL for Table STD_SECTION_OBSERVATIONS
--------------------------------------------------------

  CREATE TABLE "STD_SECTION_OBSERVATIONS"
   (	"SECTION_NAME" VARCHAR2(100),
	"SEQUENCE" NUMBER(2,0),
	"OBSERVATION_CODE" VARCHAR2(100),
	"KEY" VARCHAR2(4000),
	"CHECKBOX" VARCHAR2(10)
   ) ;
--------------------------------------------------------
--  DDL for Table CRF_RESULTS
--------------------------------------------------------

  CREATE TABLE "CRF_RESULTS"
   (	"STUDY_ID" VARCHAR2(100),
	"CASE_RECID" NUMBER(38,0),
	"SECTION_NAME" VARCHAR2(100),
	"ROW_INDEX" VARCHAR2(100),
	"PARENT_ROW_INDEX" VARCHAR2(100),
