	"OBSERVATION_VALUE" VARCHAR2(4000)
   ) ;

REM INSERTING into CRF_SECTIONS
SET DEFINE OFF;
REM INSERTING into STD_SECTIONS
SET DEFINE OFF;
REM INSERTING into STD_SECTION_OBSERVATIONS
