--------------------------------------------------------
--  DDL for View IMAGE_QUALITY
--------------------------------------------------------

  CREATE OR REPLACE EDITIONABLE VIEW "IMAGE_QUALITY" ("STUDY_ID", "CASE_RECID", "IMAGE_QUALITY_ISSUES_FLAG", "IMAGE_QUALITY_ISSUES", "IMAGE_QUALITY_COMMENTS") AS
  select "STUDY_ID","CASE_RECID","IMAGE_QUALITY_ISSUES_FLAG","IMAGE_QUALITY_ISSUES","IMAGE_QUALITY_COMMENTS" from
(
select study_id, case_recid, OBSERVATION_CODE, observation_value from crf_results
where section_name in (
'IMAGE_QUALITY'
)
order by study_id, case_recid, OBSERVATION_CODE
)
pivot
(
min(observation_value)
for observation_code in (
'IMAGE_QUALITY_ISSUES_FLAG' IMAGE_QUALITY_ISSUES_FLAG,
'IMAGE_QUALITY_ISSUES' IMAGE_QUALITY_ISSUES,
'IMAGE_QUALITY_COMMENTS' IMAGE_QUALITY_COMMENTS
)
)
;
