(
select study_id, case_recid, section_name as LESION_TYPE, row_index, parent_row_index, OBSERVATION_CODE, observation_value from crf_results
where section_name in (
'RECIST11_LESION_CALCULATIONS'
)
order by study_id, case_recid, section_name, row_index, OBSERVATION_CODE
)
pivot
(
min(observation_value)
for observation_code in (
'ACBSD' ACBSD,
'ACNSD' ACNSD,
'NADIR_TIMEPOINT' NADIR_TIMEPOINT,
'PCBSD' PCBSD,
'PCNSD' PCNSD,
'SUMDIAM' SUMDIAM,
'SUMNLNLD' SUMNLNLD
)
)
;
--------------------------------------------------------
--  DDL for View RECIST11_LESION_DETAILS
--------------------------------------------------------

  CREATE OR REPLACE EDITIONABLE VIEW "RECIST11_LESION_DETAILS" ("STUDY_ID", "CASE_RECID", "LESION_TYPE", "ROW_INDEX", "PARENT_ROW_INDEX", "LESION_ID", "LESION_LOCATION", "LESION_LOCATION_DESCRIPTION", "LDIAM", "LPERP", "PPD", "MEASUREMENT_UNITS", "LESION_ASSESSMENT", "LESION_COMMENTS", "OVERLAY_IMAGE_RECID", "OVERLAY_IMAGE_SERIES", "OVERLAY_IMAGE_SLICE_NO", "REASON_NOT_MEASURED", "REASON_NOT_EVALUABLE", "REASON_NOT_EVALUABLE_COMMENT", "CORRESPONDING_IMAGE_SERIES", "CORRESPONDING_IMAGE_RECID") AS
  select "STUDY_ID","CASE_RECID","LESION_TYPE","ROW_INDEX","PARENT_ROW_INDEX","LESION_ID","LESION_LOCATION","LESION_LOCATION_DESCRIPTION","LDIAM","LPERP","PPD","MEASUREMENT_UNITS","LESION_ASSESSMENT","LESION_COMMENTS","OVERLAY_IMAGE_RECID","OVERLAY_IMAGE_SERIES","OVERLAY_IMAGE_SLICE_NO","REASON_NOT_MEASURED","REASON_NOT_EVALUABLE","REASON_NOT_EVALUABLE_COMMENT","CORRESPONDING_IMAGE_SERIES","CORRESPONDING_IMAGE_RECID" from
(
select study_id, case_recid, section_name as LESION_TYPE, row_index, parent_row_index, OBSERVATION_CODE, observation_value from crf_results
where section_name in (
'RECIST11_NODAL_TARGET_LESIONS' ,
'RECIST11_NON_NODAL_TARGET_LESIONS' ,
'RECIST11_NON_TARGET_LESIONS' ,
'RECIST11_PREVNEW_EQUIVOCAL_LESIONS' ,
'RECIST11_NEW_EQUIVOCAL_LESIONS' ,
'RECIST11_PREVNEW_UNEQUIVOCAL_LESIONS' ,
'RECIST11_NEW_UNEQUIVOCAL_LESIONS'
)
order by study_id, case_recid, section_name, row_index, OBSERVATION_CODE
)
pivot
(
min(observation_value)
for observation_code in (
'LESION_ID' LESION_ID,
'LESION_LOCATION' LESION_LOCATION,
'LESION_LOCATION_DESCRIPTION' LESION_LOCATION_DESCRIPTION,
'LDIAM' LDIAM,
'LPERP' LPERP,
'PPD' PPD,
'MEASUREMENT_UNITS' MEASUREMENT_UNITS,
'LESION_ASSESSMENT' LESION_ASSESSMENT,
'LESION_COMMENTS' LESION_COMMENTS,
'OVERLAY_IMAGE_RECID' OVERLAY_IMAGE_RECID,
'OVERLAY_IMAGE_SERIES' OVERLAY_IMAGE_SERIES,
'OVERLAY_IMAGE_SLICE_NO' OVERLAY_IMAGE_SLICE_NO,
'REASON_NOT_MEASURED' REASON_NOT_MEASURED,
'REASON_NOT_EVALUABLE' REASON_NOT_EVALUABLE,
'REASON_NOT_EVALUABLE_COMMENT' REASON_NOT_EVALUABLE_COMMENT,
'CORRESPONDING_IMAGE_SERIES' CORRESPONDING_IMAGE_SERIES,
'CORRESPONDING_IMAGE_RECID' CORRESPONDING_IMAGE_RECID
)
)
;
